1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Damage = { itemType: string; amount: number };
4	type ClaimStep = {
5	  op: "claim";
6	  policy: number;
7	  incident: { cause: string; damages: Damage[] };
8	};
9	type Step = QuoteStep | ClaimStep;
10	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
11	type StepResult = { premium: number } | { payout: number; remainingCap: number };
12	
13	const PROCESSING_FEE = 5;
14	const FIRST_INSURANCE_SURCHARGE = 0.1;
15	const CURSED_SURCHARGE = 0.5;
16	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
17	const HIGH_ENCHANTMENT_THRESHOLD = 5;
18	
19	const BASE_PREMIUMS: Record<string, number> = {
20	  sword: 100,
21	  amulet: 60,
22	  staff: 80,
23	  potion: 40,
24	  rune: 25,
25	  moonstone: 25,
26	};
27	
28	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
29	const BLOCK_BASE = 60;
30	const BLOCK_SIZE = 3;
31	const LOYALTY_YEARS_THRESHOLD = 2;
32	const LOYALTY_DISCOUNT_RATE = 0.2;
33	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
34	
35	function withFirstInsurance(base: number): number {
36	  return base + base * FIRST_INSURANCE_SURCHARGE;
37	}
38	
39	function itemBase(item: Item): number {
40	  return BASE_PREMIUMS[item.type];
41	}
42	
43	function groupByType(items: Item[]): Map<string, Item[]> {
44	  const groups = new Map<string, Item[]>();
45	  for (const item of items) {
46	    const list = groups.get(item.type) ?? [];
47	    list.push(item);
48	    groups.set(item.type, list);
49	  }
50	  return groups;
51	}
52	
53	function componentGroupBase(group: Item[]): number {
54	  const blocks = Math.floor(group.length / BLOCK_SIZE);
55	  const remainder = group.length - blocks * BLOCK_SIZE;
56	  return blocks * BLOCK_BASE + remainder * itemBase(group[0]);
57	}
58	
59	function surchargeWhen(condition: boolean, base: number, rate: number): number {
60	  return condition ? base * rate : 0;
61	}
62	
63	function itemPremium(item: Item): number {
64	  const base = itemBase(item);
65	  const isHighlyEnchanted = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
66	  const curseSurcharge = surchargeWhen(item.cursed === true, base, CURSED_SURCHARGE);
67	  const enchantmentSurcharge = surchargeWhen(isHighlyEnchanted, base, HIGH_ENCHANTMENT_SURCHARGE);
68	  return withFirstInsurance(base) + curseSurcharge + enchantmentSurcharge;
69	}
70	
71	function partitionItems(items: Item[]): { components: Item[]; others: Item[] } {
72	  const components: Item[] = [];
73	  const others: Item[] = [];
74	  for (const item of items) {
75	    (COMPONENT_TYPES.has(item.type) ? components : others).push(item);
76	  }
77	  return { components, others };
78	}
79	
80	function componentGroupBases(components: Item[]): number[] {
81	  const bases: number[] = [];
82	  for (const [, group] of groupByType(components)) {
83	    bases.push(componentGroupBase(group));
84	  }
85	  return bases;
86	}
87	
88	function sumBy<T>(items: T[], fn: (item: T) => number): number {
89	  return items.reduce((sum, item) => sum + fn(item), 0);
90	}
91	
92	function quotePremium(items: Item[], yearsWithMHPCO: number, isFirstContract: boolean): number {
93	  const { components, others } = partitionItems(items);
94	  const groupBases = componentGroupBases(components);
95	  const othersTotal = sumBy(others, itemPremium);
96	  const componentsTotal = sumBy(groupBases, withFirstInsurance);
97	  const policyBase = sumBy(others, itemBase) + sumBy(groupBases, (base) => base);
98	  const loyaltyDiscount = surchargeWhen(
99	    yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
100	    policyBase,
101	    LOYALTY_DISCOUNT_RATE,
102	  );
103	  const followUpDiscount = surchargeWhen(
104	    !isFirstContract,
105	    policyBase,
106	    FOLLOW_UP_DISCOUNT_RATE,
107	  );
108	  return Math.ceil(othersTotal + componentsTotal - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
109	}
110	
111	const DEDUCTIBLE = 100;
112	const CAP_MULTIPLIER = 2;
113	
114	const INSURANCE_VALUES: Record<string, number> = {
115	  sword: 1000,
116	  amulet: 600,
117	  staff: 800,
118	  potion: 400,
119	  rune: 250,
120	  moonstone: 250,
121	};
122	
123	type Policy = { items: Item[]; insuranceSum: number; remainingCap: number };
124	
125	function policyInsuranceSum(items: Item[]): number {
126	  return sumBy(items, (item) => INSURANCE_VALUES[item.type]);
127	}
128	
129	function damagePayout(damage: Damage): number {
130	  return damage.amount - DEDUCTIBLE;
131	}
132	
133	function processClaim(step: ClaimStep, policies: Policy[]): StepResult {
134	  const policy = policies[step.policy];
135	  const payout = sumBy(step.incident.damages, damagePayout);
136	  policy.remainingCap -= payout;
137	  return { payout, remainingCap: policy.remainingCap };
138	}
139	
140	export function runScenario(scenario: Scenario): { results: StepResult[] } {
141	  const policies: Policy[] = [];
142	  const results: StepResult[] = scenario.steps.map((step, index) => {
143	    if (step.op === "claim") {
144	      return processClaim(step, policies);
145	    }
146	    const insuranceSum = policyInsuranceSum(step.items);
147	    policies.push({
148	      items: step.items,
149	      insuranceSum,
150	      remainingCap: CAP_MULTIPLIER * insuranceSum,
151	    });
152	    return {
153	      premium: quotePremium(step.items, scenario.customer.yearsWithMHPCO, index === 0),
154	    };
155	  });
156	  return { results };
157	}
